/**
 * Custom hook for handling media uploads (images and videos) with immediate preview
 * Author: generated by Amazon Q
 * Created: 2024-12-20
 */

import { useState, useCallback } from 'react';

interface UseMediaUploadOptions {
  type: 'logo' | 'logo-light' | 'logo-dark' | 'favicon' | 'media';
  onSuccess?: (url: string) => void;
  onError?: (error: string) => void;
}

interface UseMediaUploadReturn {
  preview: string;
  isUploading: boolean;
  uploadMedia: (file: File) => Promise<void>;
  uploadImage: (file: File) => Promise<void>; // Backward compatibility
  setPreview: (url: string) => void;
  clearPreview: () => void;
  isVideo: boolean;
}

export function useImageUpload({ 
  type, 
  onSuccess, 
  onError 
}: UseMediaUploadOptions): UseMediaUploadReturn {
  const [preview, setPreview] = useState<string>('');
  const [isUploading, setIsUploading] = useState(false);

  // Check if current preview is a video
  const isVideo = preview ? (
    preview.includes('.mp4') || 
    preview.includes('.webm') || 
    preview.includes('video/') ||
    preview.includes('.mov') ||
    preview.includes('.avi')
  ) : false;

  const uploadMedia = useCallback(async (file: File) => {
    if (!file) return;

    setIsUploading(true);

    // Create immediate preview
    const previewUrl = URL.createObjectURL(file);
    setPreview(previewUrl);

    const formData = new FormData();
    formData.append('file', file);
    formData.append('type', type);

    try {
      const response = await fetch('/api/admin/upload', {
        method: 'POST',
        body: formData
      });

      const data = await response.json();
      
      if (response.ok && data.success) {
        // Keep the blob URL for a moment to ensure smooth transition
        setTimeout(() => {
          URL.revokeObjectURL(previewUrl);
        }, 1000);
        
        // Set server URL with cache busting
        const serverUrl = `${data.url}?t=${Date.now()}`;
        setPreview(serverUrl);
        
        // Call success with the clean server URL (without cache busting for storage)
        onSuccess?.(data.url);
      } else {
        // Revert preview on error
        URL.revokeObjectURL(previewUrl);
        setPreview('');
        onError?.(data.error || 'Upload failed');
      }
    } catch (error) {
      // Revert preview on error
      URL.revokeObjectURL(previewUrl);
      setPreview('');
      onError?.(error instanceof Error ? error.message : 'Upload failed');
    } finally {
      setIsUploading(false);
    }
  }, [type, onSuccess, onError]);

  const clearPreview = useCallback(() => {
    if (preview.startsWith('blob:')) {
      URL.revokeObjectURL(preview);
    }
    setPreview('');
  }, [preview]);

  return {
    preview,
    isUploading,
    uploadMedia,
    uploadImage: uploadMedia, // Backward compatibility
    setPreview,
    clearPreview,
    isVideo
  };
}